<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background-color: #1a1a1a;
            color: #fff;
            font-family: Arial, sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
        }

        .container {
            text-align: center;
        }

        h1 {
            margin-bottom: 20px;
            font-size: 2.5em;
        }

        .info {
            margin-bottom: 20px;
            display: flex;
            justify-content: center;
            gap: 30px;
            align-items: center;
        }

        #score {
            font-size: 1.5em;
            font-weight: bold;
        }

        #reset {
            padding: 10px 20px;
            font-size: 1em;
            background-color: #4CAF50;
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            transition: background-color 0.3s;
        }

        #reset:hover {
            background-color: #45a049;
        }

        #board {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            grid-gap: 10px;
            background-color: #333;
            padding: 10px;
            border-radius: 5px;
            width: 320px;
            height: 320px;
            margin: 0 auto;
        }

        .tile {
            background-color: #444;
            border-radius: 3px;
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 2em;
            font-weight: bold;
            color: #fff;
        }

        .tile[data-value="2"] { background-color: #eee; color: #333; }
        .tile[data-value="4"] { background-color: #ede0c8; color: #333; }
        .tile[data-value="8"] { background-color: #f2b179; color: #f9f6f2; }
        .tile[data-value="16"] { background-color: #f59563; color: #f9f6f2; }
        .tile[data-value="32"] { background-color: #f67c5f; color: #f9f6f2; }
        .tile[data-value="64"] { background-color: #f65e3b; color: #f9f6f2; }
        .tile[data-value="128"] { background-color: #edcf72; color: #095f6b; font-size: 1.8em; }
        .tile[data-value="256"] { background-color: #edcc61; color: #095f6b; font-size: 1.8em; }
        .tile[data-value="512"] { background-color: #edc850; color: #095f6b; font-size: 1.8em; }
        .tile[data-value="1024"] { background-color: #edc53f; color: #095f6b; font-size: 1.5em; }
        .tile[data-value="2048"] { background-color: #edc22e; color: #095f6b; font-size: 1.5em; }
        .tile[data-value="0"] { background-color: #444; color: transparent; }
    </style>
</head>
<body>
    <div class="container">
        <h1>2048</h1>
        <div class="info">
            <div>Score: <span id="score">0</span></div>
            <button id="reset">New Game</button>
        </div>
        <div id="board"></div>
    </div>

    <script>
        class Game2048 {
            constructor() {
                this.size = 4;
                this.gridData = Array(this.size * this.size).fill(0);
                this.scoreValue = 0;
                this.initBoard();
            }

            reset() {
                this.gridData = Array(this.size * this.size).fill(0);
                this.scoreValue = 0;
                this.addNewTile();
                this.addNewTile();
                this.render();
            }

            board() {
                const result = [];
                for (let i = 0; i < this.size; i++) {
                    result.push(this.gridData.slice(i * this.size, (i + 1) * this.size));
                }
                return result;
            }

            setBoard(arr) {
                this.gridData = [];
                for (let i = 0; i < this.size; i++) {
                    for (let j = 0; j < this.size; j++) {
                        this.gridData.push(arr[i][j]);
                    }
                }
                this.render();
            }

            score() {
                return this.scoreValue;
            }

            initBoard() {
                this.addNewTile();
                this.addNewTile();
                this.render();
            }

            addNewTile() {
                const emptyIndices = this.gridData
                    .map((val, idx) => val === 0 ? idx : -1)
                    .filter(idx => idx !== -1);

                if (emptyIndices.length > 0) {
                    const randomIdx = emptyIndices[Math.floor(Math.random() * emptyIndices.length)];
                    this.gridData[randomIdx] = Math.random() < 0.9 ? 2 : 4;
                }
            }

            move(direction) {
                const before = JSON.stringify(this.gridData);

                if (direction === 'left') this.moveLeft();
                else if (direction === 'right') this.moveRight();
                else if (direction === 'up') this.moveUp();
                else if (direction === 'down') this.moveDown();

                const after = JSON.stringify(this.gridData);
                const changed = before !== after;

                if (changed) {
                    this.addNewTile();
                }

                this.render();
                return changed;
            }

            moveLeft() {
                for (let i = 0; i < this.size; i++) {
                    this.slideAndMergeRow(i * this.size, i * this.size + this.size, 1);
                }
            }

            moveRight() {
                for (let i = 0; i < this.size; i++) {
                    this.slideAndMergeRow(i * this.size + this.size - 1, i * this.size - 1, -1);
                }
            }

            moveUp() {
                for (let j = 0; j < this.size; j++) {
                    this.slideAndMergeRow(j, j + this.size * this.size, this.size);
                }
            }

            moveDown() {
                for (let j = 0; j < this.size; j++) {
                    this.slideAndMergeRow(j + this.size * (this.size - 1), j - this.size, -this.size);
                }
            }

            slideAndMergeRow(start, end, step) {
                const indices = [];
                for (let i = start; i !== end; i += step) {
                    indices.push(i);
                }

                const values = indices.map(i => this.gridData[i]).filter(v => v !== 0);

                const merged = [];
                let i = 0;
                while (i < values.length) {
                    if (i + 1 < values.length && values[i] === values[i + 1]) {
                        const mergedValue = values[i] * 2;
                        merged.push(mergedValue);
                        this.scoreValue += mergedValue;
                        i += 2;
                    } else {
                        merged.push(values[i]);
                        i += 1;
                    }
                }

                while (merged.length < this.size) {
                    merged.push(0);
                }

                for (let j = 0; j < indices.length; j++) {
                    this.gridData[indices[j]] = merged[j];
                }
            }

            render() {
                const boardEl = document.getElementById('board');
                boardEl.innerHTML = '';

                for (let i = 0; i < this.size; i++) {
                    for (let j = 0; j < this.size; j++) {
                        const value = this.gridData[i * this.size + j];
                        const tile = document.createElement('div');
                        tile.className = 'tile';
                        tile.setAttribute('data-value', value);
                        tile.textContent = value === 0 ? '' : value;
                        boardEl.appendChild(tile);
                    }
                }

                document.getElementById('score').textContent = this.scoreValue;
            }
        }

        const game = new Game2048();

        window.game = {
            size: 4,
            reset() { game.reset(); },
            move(direction) { return game.move(direction); },
            board() { return game.board(); },
            setBoard(arr) { game.setBoard(arr); },
            score() { return game.score(); }
        };

        document.getElementById('reset').addEventListener('click', () => game.reset());

        document.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowLeft') {
                e.preventDefault();
                game.move('left');
            } else if (e.key === 'ArrowRight') {
                e.preventDefault();
                game.move('right');
            } else if (e.key === 'ArrowUp') {
                e.preventDefault();
                game.move('up');
            } else if (e.key === 'ArrowDown') {
                e.preventDefault();
                game.move('down');
            }
        });
    </script>
</body>
</html>
